#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int *parent;
    int *sz;
    int components;
} DSU;

int find(DSU *d, int x) {
    if (d->parent[x] != x) d->parent[x] = find(d, d->parent[x]);
    return d->parent[x];
}

void unite(DSU *d, int a, int b) {
    a = find(d, a);
    b = find(d, b);
    if (a == b) return;
    if (d->sz[a] < d->sz[b]) { int tmp = a; a = b; b = tmp; }
    d->parent[b] = a;
    d->sz[a] += d->sz[b];
    d->components--;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, Q; scanf("%d %d", &N, &Q);
        DSU d; d.parent = (int*)malloc((N+1)*sizeof(int));
        d.sz = (int*)malloc((N+1)*sizeof(int));
        for (int i=1;i<=N;i++) { d.parent[i]=i; d.sz[i]=1; }
        d.components = N;
        for (int i=0;i<Q;i++) {
            int type; scanf("%d", &type);
            if (type==1) {
                int A,B; scanf("%d %d", &A, &B);
                unite(&d, A, B);
            } else if (type==2) {
                int A,B; scanf("%d %d", &A, &B);
                if (find(&d, A)==find(&d, B)) printf("YES\n");
                else printf("NO\n");
            } else if (type==3) {
                printf("%d\n", d.components);
            }
        }
        free(d.parent); free(d.sz);
    }
    return 0;
}

