#include <bits/stdc++.h>
using namespace std;

struct DSU {
    vector<int> p, sz;
    int components;
    DSU(int n=0){init(n);}    
    void init(int n){p.resize(n+1); sz.assign(n+1,1); iota(p.begin(), p.end(), 0); components=n;}
    int find(int x){return p[x]==x?x:p[x]=find(p[x]);}
    void unite(int a,int b){a=find(a); b=find(b); if(a==b) return; if(sz[a]<sz[b]) swap(a,b); p[b]=a; sz[a]+=sz[b]; components--;}
};

int main(){ios::sync_with_stdio(false);cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0; while(T--){
        int N,Q;cin>>N>>Q; DSU dsu(N);
        for(int i=0;i<Q;i++){
            int type;cin>>type;
            if(type==1){int A,B;cin>>A>>B; dsu.unite(A,B);} 
