import java.io.*;
import java.util.*;

public class Main {
    static class DSU {
        int[] parent, size;
        int components;
        DSU(int n){
            parent = new int[n+1];
            size = new int[n+1];
            for(int i=1;i<=n;i++){parent[i]=i; size[i]=1;}
            components = n;
        }
        int find(int x){
            if(parent[x]!=x) parent[x]=find(parent[x]);
            return parent[x];
        }
        void unite(int a,int b){
            a=find(a); b=find(b);
            if(a==b) return;
            if(size[a]<size[b]){int t=a;a=b;b=t;}
            parent[b]=a; size[a]+=size[b]; components--;
        }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while(T-- > 0){
            int N = fs.nextInt();
            int Q = fs.nextInt();
            DSU dsu = new DSU(N);
            for(int i=0;i<Q;i++){
                int type = fs.nextInt();
                if(type==1){
                    int A = fs.nextInt();
                    int B = fs.nextInt();
                    dsu.unite(A,B);
                } else if(type==2){
                    int A = fs.nextInt();
                    int B = fs.nextInt();
                    out.append(dsu.find(A)==dsu.find(B) ? "YES" : "NO").append('\n');
                } else if(type==3){
                    out.append(dsu.components).append('\n');
                }
            }
        }
        System.out.print(out.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){this.in = in;}
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

