#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); Q = int(next(it))
        parent = list(range(N+1))
        size = [1]*(N+1)
        components = N
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def unite(a,b):
            nonlocal components
            a = find(a); b = find(b)
            if a == b:
                return
            if size[a] < size[b]:
                a,b = b,a
            parent[b] = a
            size[a] += size[b]
            components -= 1
        for __ in range(Q):
            typ = int(next(it))
            if typ == 1:
                A = int(next(it)); B = int(next(it))
                unite(A,B)
            elif typ == 2:
                A = int(next(it)); B = int(next(it))
                out_lines.append("YES" if find(A)==find(B) else "NO")
            else:  # typ == 3
                out_lines.append(str(components))
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

